import{_ as o,o as t,c as d,a2 as r}from"./chunks/framework.IwO0Hdn_.js";const g=JSON.parse('{"title":"Descripción del Proyecto","description":"","frontmatter":{},"headers":[],"relativePath":"0_descripcion_proyecto.md","filePath":"0_descripcion_proyecto.md","lastUpdated":null}'),a={name:"0_descripcion_proyecto.md"};function i(s,e,n,c,l,p){return t(),d("div",null,[...e[0]||(e[0]=[r('<h1 id="descripcion-del-proyecto" tabindex="-1">Descripción del Proyecto <a class="header-anchor" href="#descripcion-del-proyecto" aria-label="Permalink to &quot;Descripción del Proyecto&quot;">​</a></h1><p>Quiero diseñar un sistema para administrar los logs de múltiples aplicaciones. A partir de una base de datos PostgreSQL donde estarán los logs categorizados por tipo <code>[Critical, High, Medium, Low, Others]</code>, la idea es tener un panel de administración y gestión de los mismos.</p><p>El panel tendrá un <strong>dashboard</strong> donde se vean cards con los contadores de error por tipo. Al pulsar una card se accede a una tabla paginada con filtros. Al pulsar sobre una fila se abre la vista detalle. Desde el detalle se puede archivar el log en un histórico añadiendo comentarios con texto enriquecido. Habrá también una pestaña dedicada al histórico con filtros y ordenación. Adicionalmente existirá un módulo independiente de <strong>catálogo de códigos de error</strong> (CRUD completo) para que los equipos registren y clasifiquen sus errores de forma normalizada.</p><hr><h2 id="decisiones-de-diseno" tabindex="-1">Decisiones de Diseño <a class="header-anchor" href="#decisiones-de-diseno" aria-label="Permalink to &quot;Decisiones de Diseño&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pregunta</th><th>Decisión</th></tr></thead><tbody><tr><td>¿Multi-tenant o monocliente?</td><td><strong>Monocliente</strong> — múltiples apps del mismo sistema, todos los usuarios ven todo</td></tr><tr><td>¿Cómo llegan los logs?</td><td><strong>Ya existe un flujo n8n</strong> que inserta en PostgreSQL — no hay que diseñar la ingesta</td></tr><tr><td>¿Qué es el histórico?</td><td>Log con <strong>campo de persistencia permanente</strong>. Al archivar, desaparece de la vista de logs activos</td></tr><tr><td>¿Solucionado vs Archivar?</td><td><strong>Dos acciones distintas</strong>: &quot;Solucionado&quot; (F-02.8) descarta el log sin crear registro en el histórico ni requerir comentario. &quot;Guardar en Histórico&quot; archiva con comentario obligatorio, descripción y URL Tutorial</td></tr><tr><td>¿Múltiples comentarios por log archivado?</td><td><strong>Sí</strong>, hilo de comentarios por entrada archivada. Solo se muestran en Histórico</td></tr><tr><td>¿Cuántos usuarios?</td><td><strong>Varios usuarios</strong> del equipo dev. El administrador llega autenticado desde API externa</td></tr><tr><td>¿Tiempo real?</td><td><strong>SSE (Server-Sent Events)</strong> para el dashboard — eficiente y sin complejidad de WebSockets</td></tr><tr><td>¿Autenticación propia?</td><td><strong>No</strong> — el usuario llega autenticado por un sistema externo. Se simula con mock de sesión durante desarrollo</td></tr><tr><td>¿Responsive / Mobile?</td><td><strong>Sí</strong> — diseño mobile-first. Las filas de tabla son clicables en su totalidad (sin botón &quot;Ver&quot; independiente)</td></tr><tr><td>¿Idiomas?</td><td><strong>i18n con archivos Laravel lang</strong>. UI en español. Base para soporte futuro en valenciano. Código en inglés</td></tr></tbody></table><hr><h2 id="stack-tecnologico-definitivo" tabindex="-1">Stack Tecnológico Definitivo <a class="header-anchor" href="#stack-tecnologico-definitivo" aria-label="Permalink to &quot;Stack Tecnológico Definitivo&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Capa</th><th>Tecnología</th><th>Notas</th></tr></thead><tbody><tr><td>Backend</td><td><strong>Laravel 12 (PHP)</strong></td><td>Routing web, controladores, modelos Eloquent</td></tr><tr><td>Frontend dinámico</td><td><strong>Livewire 3</strong></td><td>Componentes reactivos server-side. Sin SPA separada</td></tr><tr><td>Frontend estático</td><td><strong>Blade + Alpine.js</strong></td><td>Componentes reutilizables, microinteracciones</td></tr><tr><td>Rich Text</td><td><strong>TipTap 2</strong> (con Alpine.js)</td><td>Editor embebido en componentes Livewire vía JS bridge</td></tr><tr><td>Base de datos</td><td><strong>PostgreSQL</strong> (existente)</td><td>Tablas <code>logs</code> (read-only), <code>archived_logs</code>, <code>comments</code>, <code>error_codes</code>, <code>users</code></td></tr><tr><td>Tiempo real</td><td><strong>SSE via StreamedResponse</strong></td><td>Laravel escucha <code>pg_notify</code> y emite eventos SSE</td></tr><tr><td>Autenticación</td><td><strong>Sesión externa + mock</strong></td><td>El usuario viene de API externa. Mock de sesión en desarrollo</td></tr><tr><td>i18n</td><td><strong>Laravel Lang</strong></td><td><code>resources/lang/es/</code> y futuro <code>resources/lang/va/</code></td></tr></tbody></table><hr><h2 id="arquitectura-de-vistas-y-controladores" tabindex="-1">Arquitectura de Vistas y Controladores <a class="header-anchor" href="#arquitectura-de-vistas-y-controladores" aria-label="Permalink to &quot;Arquitectura de Vistas y Controladores&quot;">​</a></h2><p>Habrá <strong>4 controladores</strong> y <strong>3 vistas base</strong> (reutilizadas con condicionales):</p><table tabindex="0"><thead><tr><th>Controlador</th><th>Vista</th><th>Ruta</th></tr></thead><tbody><tr><td><code>DashboardController</code></td><td><code>dashboard.blade.php</code></td><td><code>/</code></td></tr><tr><td><code>LogController</code></td><td><code>logs/index.blade.php</code> + <code>logs/show.blade.php</code></td><td><code>/logs</code>, <code>/logs/{id}</code></td></tr><tr><td><code>ArchivedLogController</code></td><td>(reutiliza <code>logs/show</code>)</td><td><code>/historico</code>, <code>/historico/{id}</code></td></tr><tr><td><code>ErrorCodeController</code></td><td><code>errorcodes/index.blade.php</code> + <code>errorcodes/show.blade.php</code></td><td><code>/error-codes</code>, <code>/error-codes/{id}</code></td></tr></tbody></table><p>La <strong>vista detalle</strong> (<code>show</code>) es compartida entre Logs y Histórico, mostrando contenido diferente mediante condicionales:</p><ul><li><strong>Desde Logs activos:</strong> Título, Código Error, Mensaje, Aplicación, Descripción (solo lectura) + botón &quot;Guardar en Histórico&quot; o &quot;Ver histórico&quot;</li><li><strong>Desde Histórico:</strong> Todo lo anterior + Descripción editable + URL Tutorial + Sección Comentarios + botones &quot;Editar&quot; y &quot;Borrar&quot;</li></ul><hr><h2 id="componentes-livewire-identificados-dinamicos" tabindex="-1">Componentes Livewire Identificados (dinámicos) <a class="header-anchor" href="#componentes-livewire-identificados-dinamicos" aria-label="Permalink to &quot;Componentes Livewire Identificados (dinámicos)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Componente</th><th>Función</th></tr></thead><tbody><tr><td><code>DashboardCards</code></td><td>Cards con contadores actualizados vía SSE</td></tr><tr><td><code>LogsTable</code></td><td>Tabla paginada de logs activos con filtros (GET) y orden (POST)</td></tr><tr><td><code>ArchivedLogsTable</code></td><td>Tabla del histórico con mismos filtros/orden</td></tr><tr><td><code>LogDetail</code></td><td>Vista detalle (logs activos): mostrar datos, botón guardar/ver</td></tr><tr><td><code>ArchivedLogDetail</code></td><td>Vista detalle (histórico): editar descripción, URL tutorial, borrar</td></tr><tr><td><code>CommentSection</code></td><td>Hilo de comentarios con input sticky, paginable, editable por autor</td></tr><tr><td><code>ErrorCodesTable</code></td><td>Listado CRUD de la tabla <code>error_codes</code></td></tr><tr><td><code>ErrorCodeForm</code></td><td>Formulario crear/editar error code</td></tr><tr><td><code>ErrorCodeCommentSection</code></td><td>Hilo de comentarios por código de error (reutiliza lógica de <code>CommentSection</code>)</td></tr></tbody></table><h2 id="componentes-blade-reutilizables-estaticos" tabindex="-1">Componentes Blade Reutilizables (estáticos) <a class="header-anchor" href="#componentes-blade-reutilizables-estaticos" aria-label="Permalink to &quot;Componentes Blade Reutilizables (estáticos)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Componente</th><th>Función</th></tr></thead><tbody><tr><td><code>x-layout</code></td><td>Layout principal con nav y footer</td></tr><tr><td><code>x-nav</code></td><td>Barra de navegación (Logs / Histórico / Error Codes + Logout)</td></tr><tr><td><code>x-card</code></td><td>Card genérica del dashboard</td></tr><tr><td><code>x-badge-severity</code></td><td>Badge de color por tipo (Critical/High/Medium/Low)</td></tr><tr><td><code>x-modal-confirm</code></td><td>Modal de confirmación de acciones destructivas</td></tr></tbody></table><hr><h2 id="modulo-error-codes" tabindex="-1">Módulo Error Codes <a class="header-anchor" href="#modulo-error-codes" aria-label="Permalink to &quot;Módulo Error Codes&quot;">​</a></h2><p>El equipo necesita un <strong>catálogo normalizado de códigos de error</strong> para que cuando un <code>try/catch</code> falle, devuelva un código predefinido y no mensajes arbitrarios.</p><ul><li>Campos: <code>código</code> (incremental por aplicación), <code>nombre/título</code>, <code>aplicación</code>, <code>descripción del contexto del error</code>, <code>fichero</code>, <code>línea</code></li><li><strong>Clave compuesta</strong>: <code>(código + aplicación)</code> — el mismo código puede existir en distintas aplicaciones</li><li>CRUD completo: crear, listar (con filtros), editar, borrar</li><li>Opcional: comentarios por error code para documentación interna</li></ul><hr><h2 id="notas-de-implementacion" tabindex="-1">Notas de Implementación <a class="header-anchor" href="#notas-de-implementacion" aria-label="Permalink to &quot;Notas de Implementación&quot;">​</a></h2><ul><li><strong>Filtros y paginación → GET</strong> (persiste en URL, compartible)</li><li><strong>Ordenación de columnas → POST</strong> (no persiste; se envía como formulario)</li><li><strong>Comentarios</strong> solo en Histórico y Error Codes. Editables únicamente por el autor</li><li>Los <strong>logs activos</strong> se borran automáticamente cada X tiempo por un proceso externo (n8n). El panel solo los lee</li><li>Los <strong>logs archivados</strong> son permanentes por defecto. La acción de borrado (F-04.9, <code>COULD</code>) es excepcional: requiere confirmación explícita, está protegida por autenticación y se registra en el log de aplicación (NFR-OBS-02). El usuario de BD del panel no tiene permiso <code>DELETE</code> sobre <code>archived_logs</code> cuando F-04.9 no está implementado; con F-04.9 activo, el delete se gestiona a nivel de autorización de aplicación (Policy), no de permisos de BD</li><li>El <strong>login</strong> no se implementa en esta aplicación (la pantalla de login está descartada del wireframe)</li><li>Los <strong>textos de la UI</strong> se externalizan en archivos <code>lang/es/</code> desde el principio</li></ul>',27)])])}const m=o(a,[["render",i]]);export{g as __pageData,m as default};
